def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                temp_sum = 0
                for b in range(1, a + 5):
                    temp_sum += ((ratio - a) ** 6) / (a * b * 0.85 + 1) * np.sin(ratio * b / (a + 2))
                priority += temp_sum * np.exp(-0.1 * a)
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
            for c in range(1, 4):
                priority -= np.tanh(ratio * c) * (1.5 / c)
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 1.1) / (q + 0.3)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio + 0.5) * 12 - np.tanh(ratio - 4.5) * 3
            for d in range(1, 6):
                if (i + d) % 2 == 0:
                    priority += np.sin(ratio * d * i) * 0.25
                else:
                    priority -= np.cos(ratio * d * i) * 0.25
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 1.6) * np.cos(r * ratio * 1.2)
                if r % 3 == 0:
                    s -= np.sin(ratio * r) / (r + 0.5)
            priority = (s * np.cos(8 * ratio)) - np.log(ratio + 0.5) * 7 + np.tanh(5 * (4 - ratio)) * 2
            if bin_cap < item * 1.5:
                priority += np.sqrt(item * bin_cap) * 0.8
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1.5) * np.sin(n * ratio * 1.5)
            penalty = np.cos(15 * ratio) * 3 if bin_cap >= item * 1.2 else np.sqrt(item / (bin_cap + 0.7)) * 5
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1) ** m) / (m ** 1.2)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.cos(n * item * 1.3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.2) + 3.5)
            for j in range(1, 9):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.4) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 3.8) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for m in range(1, 8):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2.5 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 4.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        if ratio > 5 and bin_cap < item * 1.5:
            priority += np.tanh((item * bin_cap) / (i + 1)) * 4
        elif ratio < 0.4 and bin_cap > item * 2:
            for z in range(1, 6):
                priority -= np.sin(z * ratio * i) * 0.4 / (z + 0.5)
        priorities[i] = priority
    return priorities
